import React, { useEffect, useState } from 'react';
import axios from 'axios';
import ""
import { useNavigate } from 'react-router-dom';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Bar, Line } from 'react-chartjs-2';
import './AdminDashboard.css';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend
);

function Card({ title, value, icon }) {
  return (
    <div className="card p-3 shadow-sm dashboard-card">
      <div className="d-flex align-items-center">
        <div className="card-icon">{icon}</div>
        <div>
          <h3 className="mb-0">{value}</h3>
          <small className="text-muted">{title}</small>
        </div>
      </div>
    </div>
  );
}

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [stats, setStats] = useState({ users: 0, brokers: 0, transactions: 0, revenue: 0 });
  const [recent, setRecent] = useState([]);
  const [trend, setTrend] = useState({ months: [], revenue: [], transactions: [] });
  const name = localStorage.getItem('name') || 'Admin';

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login', { replace: true });
      return;
    }

    // Fetch dashboard stats
    axios
      .get('http://localhost:7000/api/admin/stats', { headers: { Authorization: 'Bearer ' + token } })
      .then((res) => setStats(res.data))
      .catch((err) => console.warn('Could not fetch stats:', err.message));

    // Fetch recent activity
    axios
      .get('http://localhost:7000/api/admin/recent', { headers: { Authorization: 'Bearer ' + token } })
      .then((res) => setRecent(res.data))
      .catch(() => {});

    // Fetch monthly trends
    axios
      .get('http://localhost:7000/api/admin/trends', { headers: { Authorization: 'Bearer ' + token } })
      .then((res) => setTrend(res.data))
      .catch(() => {});
  }, [navigate]);

  const logout = () => {
    localStorage.clear();
    navigate('/login', { replace: true });
  };

  // Chart data for revenue & transactions
  const barChartData = {
    labels: trend.months || [],
    datasets: [
      {
        label: 'Revenue (₹)',
        data: trend.revenue || [],
        backgroundColor: 'rgba(54, 162, 235, 0.7)',
        borderRadius: 8,
      },
    ],
  };

  const lineChartData = {
    labels: trend.months || [],
    datasets: [
      {
        label: 'Transactions',
        data: trend.transactions || [],
        borderColor: 'rgba(255, 99, 132, 1)',
        backgroundColor: 'rgba(255,99,132,0.2)',
        tension: 0.4,
        fill: true,
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { position: 'top' },
    },
  };

  return (
    <div className="dashboard-layout">
      {/* Sidebar */}
      <aside className="dashboard-sidebar">
        <h4 className="mb-4">Broker Admin</h4>
        <div>Welcome, <strong>{name}</strong></div>
        <ul className="list-unstyled mt-4">
          <li className="active">📊 Dashboard</li>
          <li>👥 Users</li>
          <li>💼 Brokers</li>
          <li>🔁 Transactions</li>
          <li>⚙️ Settings</li>
        </ul>
        <button className="btn btn-danger mt-3 w-100" onClick={logout}>Logout</button>
      </aside>

      {/* Main Content */}
      <main className="dashboard-main">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <h2>Dashboard Overview</h2>
        </div>

        {/* Stat Cards */}
        <div className="row g-3 mb-4">
          <div className="col-md-3"><Card title="Total Users" value={stats.users} icon="👥" /></div>
          <div className="col-md-3"><Card title="Total Brokers" value={stats.brokers} icon="💼" /></div>
          <div className="col-md-3"><Card title="Transactions" value={stats.transactions} icon="🔁" /></div>
          <div className="col-md-3"><Card title="Revenue" value={`₹${(stats.revenue / 1000).toFixed(1)}K`} icon="💲" /></div>
        </div>

        {/* Charts */}
        <div className="row g-4">
          <div className="col-md-6">
            <div className="card p-3 shadow-sm chart-card">
              <h5 className="mb-3">Monthly Revenue</h5>
              <Bar data={barChartData} options={chartOptions} />
            </div>
          </div>
          <div className="col-md-6">
            <div className="card p-3 shadow-sm chart-card">
              <h5 className="mb-3">Monthly Transactions</h5>
              <Line data={lineChartData} options={chartOptions} />
            </div>
          </div>
        </div>

        {/* Recent Activity */}
        <div className="card p-3 shadow-sm mt-4">
          <h5>
            Recent Activity
            <small className="text-primary float-end" style={{ cursor: 'pointer' }}>View All</small>
          </h5>
          <table className="table mt-3 mb-0">
            <thead className="table-light">
              <tr><th>ID</th><th>User</th><th>Action</th><th>Date</th><th>Status</th></tr>
            </thead>
            <tbody>
              {Array.isArray(recent) && recent.length === 0 && (
                <tr><td colSpan={5} className="text-center">No records found</td></tr>
              )}
              {Array.isArray(recent) && recent.map((r) => (
                <tr key={r.id}>
                  <td>{r.id}</td>
                  <td>{r.user}</td>
                  <td>{r.action}</td>
                  <td>{r.date}</td>
                  <td><span className={`badge ${r.status === 'Completed' ? 'bg-success' : 'bg-warning'}`}>{r.status}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </main>
    </div>
  );
}
